mapper.insert:
	/** UsptBsnsCnvnHistDao.insert */
insert into uspt_bsns_cnvn_hist (
			 	 bsns_cnvn_hist_id
				,cnvn_change_req_id
				,change_iem_div_cd
				,cnvn_change_sttus_cd
				,cnvn_change_type_cd
				,resn_cn
				,attachment_group_id
				,creator_id
				,created_dt
			) values (
				 #{bsnsCnvnHistId}
				,#{cnvnChangeReqId}
				,#{changeIemDivCd}
				,#{cnvnChangeSttusCd}
				,#{cnvnChangeTypeCd}
				,#{resnCn}
				,#{attachmentGroupId}
				,#{creatorId}
				,#{createdDt}
			)

mapper.select:
/** UsptBsnsCnvnHistDao.selectUsptBsnsCnvnHistMax */
	select a.*
	from (
			select	 bsns_cnvn_hist_id
					,cnvn_change_req_id
					,change_iem_div_cd
					,cnvn_change_sttus_cd
					,cnvn_change_type_cd
					,resn_cn
					,attachment_group_id
			        ,row_number() over (order by created_dt desc) as rn
			from uspt_bsns_cnvn_hist
			where cnvn_change_req_id = #{cnvnChangeReqId}
			   and change_iem_div_cd  = #{changeIemDivCd}
		) a
	  where a.rn = 1

/** UsptBsnsCnvnHistDao.selectBsnsCnvnHist */
	select  to_char(ubch.created_dt,'yyyy-mm-dd HH24:MI:SS') as hist_dt
			, ubch.cnvn_change_sttus_cd
			, fn_cmm_get_code_nm('CNVN_CHANGE_STTUS', ubch.cnvn_change_sttus_cd) as cnvn_change_sttus_nm	/*협약변경상태명*/
			, ubch.resn_cn
			, (select member_nm   	from cmmt_member cm   	   where cm.member_id = ubch.creator_id)		as member_nm							/*회원명 */
			, ubch.creator_id as  member_id
	from uspt_bsns_cnvn_hist ubch
	where ubch.cnvn_change_req_id = #{cnvnChangeReqId}
	   and ubch.change_iem_div_cd  = #{changeIemDivCd}
